import{_ as i,o as e,c as n,ae as a}from"./chunks/framework.B6gjLfeO.js";const b=JSON.parse('{"title":"Branch Attribution Logic & Settings","description":"","frontmatter":{"title":"Branch Attribution Logic & Settings","slug":"branch-attribution-logic-settings"},"headers":[],"relativePath":"marketer-hub/branch-attribution-logic-settings.md","filePath":"marketer-hub/branch-attribution-logic-settings.md"}'),r={name:"marketer-hub/branch-attribution-logic-settings.md"};function o(s,t,l,c,u,d){return e(),n("div",null,[...t[0]||(t[0]=[a('<p>To accurately measure and attribute interactions (installs and in-app events) that users take with your app, Branch uses several different types of attribution. The attribution method Branch applies depends on a combination of factors, like platform/app store, engagement type, and conversion type. Branch’s attribution methods are “stack-ranked” to ensure the highest level of accuracy.</p><h2 id="key-takeaways" tabindex="-1">Key takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key takeaways&quot;">​</a></h2><ul><li>Clicks take precedence over impressions.</li><li>Methods using deterministic 1:1 attribution (via unique identifiers/IDs) take precedence over methods using probabilistic (not 1:1) attribution.</li><li>By ensuring Branch receives the necessary information (i.e. unique identifiers) to implement deterministic click attribution, we ensure not only accurate attribution for our clients but give the appropriate level of priority to all incoming clicks/impressions.</li></ul><h2 id="attribution-methods-in-order-of-operation" tabindex="-1">Attribution Methods in Order of Operation <a class="header-anchor" href="#attribution-methods-in-order-of-operation" aria-label="Permalink to &quot;Attribution Methods in Order of Operation&quot;">​</a></h2><p><strong>1. Deterministic Click Attribution</strong></p><ul><li><p>iOS NativeLink™</p></li><li><p>Google Play Install Referrer</p></li><li><p>Identifier Matching <em>when an identifier is provided on click, probabilistic modeling will not be used as a fallback</em></p><ul><li>Google Advertising Identifier (GAID)</li><li>Apple’s Identifier for Advertisers (IDFA)</li></ul></li><li><p>Open URL (deep link) with Click ID</p></li></ul><p><strong>2. Probabilistic Click Attribution</strong></p><ul><li><a href="./predictive-modeling.html">Predictive Modeling</a> if available, or point-in-time probabilistic modeling.</li></ul><p><strong>3. Deterministic View Attribution</strong></p><ul><li>Identifier Matching Only</li></ul><h2 id="attribution-settings" tabindex="-1">Attribution Settings <a class="header-anchor" href="#attribution-settings" aria-label="Permalink to &quot;Attribution Settings&quot;">​</a></h2><p>For detailed information on configuring attribution windows, inheritance settings, and managing attribution at the organization, app, and partner levels, see our <a href="./attribution-windows.html">Attribution Windows</a> guide.</p>',12)])])}const h=i(r,[["render",o]]);export{b as __pageData,h as default};
